import{_ as a,c as e,o as r,a1 as d}from"./chunks/framework.DILC4Csi.js";const f=JSON.parse('{"title":"平台集成: 多种协议接入 | Antigravity-Manager","description":"学习 Antigravity Tools 的平台协议接入方法。支持 OpenAI、Anthropic、Gemini 等 7 种协议的统一 API 网关转换。","frontmatter":{"title":"平台集成: 多种协议接入 | Antigravity-Manager","sidebarTitle":"接入你的 AI 平台","subtitle":"平台集成: 多种协议接入","description":"学习 Antigravity Tools 的平台协议接入方法。支持 OpenAI、Anthropic、Gemini 等 7 种协议的统一 API 网关转换。","order":200},"headers":[],"relativePath":"zh/lbjlaq/Antigravity-Manager/platforms/index.md","filePath":"zh/lbjlaq/Antigravity-Manager/platforms/index.md"}'),o={name:"zh/lbjlaq/Antigravity-Manager/platforms/index.md"};function i(l,t,n,h,s,c){return r(),e("div",null,[...t[0]||(t[0]=[d('<h1 id="平台与集成" tabindex="-1">平台与集成 <a class="header-anchor" href="#平台与集成" aria-label="Permalink to &quot;平台与集成&quot;">​</a></h1><p>Antigravity Tools 的核心能力是把多家 AI 平台的协议转换为统一的本地 API 网关。本章节详细介绍每种协议的接入方式、兼容边界和最佳实践。</p><h2 id="本章包含" tabindex="-1">本章包含 <a class="header-anchor" href="#本章包含" aria-label="Permalink to &quot;本章包含&quot;">​</a></h2><table tabindex="0"><thead><tr><th>教程</th><th>说明</th></tr></thead><tbody><tr><td><a href="./openai/">OpenAI 兼容 API</a></td><td><code>/v1/chat/completions</code> 与 <code>/v1/responses</code> 的落地策略，让 OpenAI SDK 无感接入</td></tr><tr><td><a href="./anthropic/">Anthropic 兼容 API</a></td><td><code>/v1/messages</code> 与 Claude Code 的关键契约，支撑思维链、系统提示词等核心能力</td></tr><tr><td><a href="./gemini/">Gemini 原生 API</a></td><td><code>/v1beta/models</code> 以及 Google SDK 的端点接入，支持 <code>x-goog-api-key</code> 兼容</td></tr><tr><td><a href="./imagen/">Imagen 3 图片生成</a></td><td>OpenAI Images 参数 <code>size</code>/<code>quality</code> 的自动映射，支持任意宽高比</td></tr><tr><td><a href="./audio/">音频转录</a></td><td><code>/v1/audio/transcriptions</code> 的限制与大包体处理</td></tr><tr><td><a href="./mcp/">MCP 端点</a></td><td>把 Web Search/Reader/Vision 作为可调用工具暴露出去</td></tr><tr><td><a href="./cloudflared/">Cloudflared 隧道</a></td><td>一键把本地 API 安全暴露到公网（并非默认安全）</td></tr></tbody></table><h2 id="学习路径建议" tabindex="-1">学习路径建议 <a class="header-anchor" href="#学习路径建议" aria-label="Permalink to &quot;学习路径建议&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">推荐顺序</p><ol><li><strong>先学你要用的协议</strong>：如果你用 Claude Code，先看 <a href="./anthropic/">Anthropic 兼容 API</a>；如果用 OpenAI SDK，先看 <a href="./openai/">OpenAI 兼容 API</a></li><li><strong>再学 Gemini 原生</strong>：了解 Google SDK 的直接接入方式</li><li><strong>按需学习扩展功能</strong>：图片生成、音频转录、MCP 工具</li><li><strong>最后学隧道</strong>：需要公网暴露时再看 <a href="./cloudflared/">Cloudflared 隧道</a></li></ol></div><p><strong>快速选择</strong>：</p><table tabindex="0"><thead><tr><th>你的场景</th><th>推荐先看</th></tr></thead><tbody><tr><td>使用 Claude Code CLI</td><td><a href="./anthropic/">Anthropic 兼容 API</a></td></tr><tr><td>使用 OpenAI Python SDK</td><td><a href="./openai/">OpenAI 兼容 API</a></td></tr><tr><td>使用 Google 官方 SDK</td><td><a href="./gemini/">Gemini 原生 API</a></td></tr><tr><td>需要 AI 画图</td><td><a href="./imagen/">Imagen 3 图片生成</a></td></tr><tr><td>需要语音转文字</td><td><a href="./audio/">音频转录</a></td></tr><tr><td>需要联网搜索/网页阅读</td><td><a href="./mcp/">MCP 端点</a></td></tr><tr><td>需要远程访问</td><td><a href="./cloudflared/">Cloudflared 隧道</a></td></tr></tbody></table><h2 id="前置条件" tabindex="-1">前置条件 <a class="header-anchor" href="#前置条件" aria-label="Permalink to &quot;前置条件&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">开始前请确认</p><ul><li>已完成 <a href="./../start/installation/">安装与升级</a></li><li>已完成 <a href="./../start/add-account/">添加账号</a></li><li>已完成 <a href="./../start/proxy-and-first-client/">启动本地反代</a>（至少能访问 <code>/healthz</code>）</li></ul></div><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>学完本章节后，你可以继续学习：</p><ul><li><a href="./../advanced/">进阶配置</a>：模型路由、配额治理、高可用调度等高级功能</li><li><a href="./../faq/">常见问题</a>：遇到 401/404/429 等错误时的排查指南</li></ul>',13)])])}const A=a(o,[["render",i]]);export{f as __pageData,A as default};
